where.trim:
a.special_id=b.id and a.recovery=0 and a.recovery=b.recovery
and a.id = #{id}
and b.id = #{special_id}
and b.store_id = #{store_id}
and a.status = #{status}
and a.is_show = #{is_show}
and a.name = #{sessionName}
and a.special_id = #{specialId}
and (a.id = #{keyName} or a.name like concat('%',#{keyName},'%'))
and a.name = #{sessionName}
and a.start_date   >=   #{startDate}
and a.end_date   <=   #{endDate}

    
        #{status,jdbcType=INTEGER}

mapper.select:
select a.id,b.id specialId,a.name sessionName,b.name,a.start_date,a.end_date,a.status,a.is_show,a.add_date,b.start_date specialStartDate, b.end_date specialEndDate,b.img,b.content,b.unit,b.promise_amt,b.number,b.mark_up_amt from lkt_auction_session a,lkt_auction_special b
a.add_date ${add_date_sort},
limit #{pageStart},#{pageEnd}

where.trim:
a.id=b.pid and a.recycle=0 and b.recycle=a.recycle and substring_index(substring_index(a.product_class, '-', 2), '-', -1)=c.cid
and not exists (select distinct y.id from lkt_auction_session x,lkt_auction_product y,lkt_auction_goods z where x.recovery=0 and x.recovery=y.recovery and x.recovery=z.recovery and x.status!=3 and y.status not in (3,4,5) and z.attr_id= y.attr_id and y.attr_id=b.id)
and a.store_id = #{store_id}
and a.active = #{active}
and a.mch_id = #{mchId}
AND a.product_class like CONCAT('%-',#{classId},'-%')
and ( a.id=#{key} or a.product_title like concat('%',#{key},'%') )

mapper.select:
select a.id,b.id attrId,a.product_title,c.pname,b.price,b.size,b.img from lkt_product_list a,lkt_configure b,lkt_product_class c


    a.add_date ${add_date_sort},

limit #{pageStart},#{pageEnd}
